def to_ascii(fen):
    board=fen.split()[0].split('/')
    lines=[]
    for i,row in enumerate(board):
        rank=8-i
        cells=[]
        for c in row:
            if c.isdigit():
                cells+=['.']*int(c)
            else:
                cells.append(c)
        lines.append(str(rank)+' '+' '.join(cells))
    lines.append('  a b c d e f g h')
    return '\n'.join(lines)
